import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Table, Thead, Tbody, Tr, Th, Td, TableCaption, Button, Flex, Box } from '@chakra-ui/react';
import { IoIosArrowDown, IoIosArrowUp } from 'lucide-react';

const TransactionTable = () => {
  const [transactionData, setTransactionData] = useState([
    { id: 1, name: 'Transaction 1', type: 'Buy', amount: 1000, date: '2023-03-20' },
    { id: 2, name: 'Transaction 2', type: 'Sell', amount: 500, date: '2023-03-21' },
    { id: 3, name: 'Transaction 3', type: 'Buy', amount: 2000, date: '2023-03-22' },
    { id: 4, name: 'Transaction 4', type: 'Sell', amount: 3000, date: '2023-03-23' },
    { id: 5, name: 'Transaction 5', type: 'Buy', amount: 4000, date: '2023-03-24' },
  ]);

  const [sortedColumn, setSortedColumn] = useState('id');
  const [isSorted, setIsSorted] = useState('asc');

  useEffect(() => {
    console.log('Sorted column:', sortedColumn);
  }, [sortedColumn]);

  const handleSort = (column) => {
    if (sortedColumn === column) {
      setIsSorted(isSorted === 'asc' ? 'desc' : 'asc');
    } else {
      setSortedColumn(column);
      setIsSorted('asc');
    }
  };

  const sortedTransactions = () => {
    if (sortedColumn === 'id') {
      return transactionData.sort((a, b) => isSorted === 'asc' ? a.id - b.id : b.id - a.id);
    } else if (sortedColumn === 'name') {
      return transactionData.sort((a, b) => isSorted === 'asc' ? a.name.localeCompare(b.name) : b.name.localeCompare(a.name));
    } else if (sortedColumn === 'type') {
      return transactionData.sort((a, b) => isSorted === 'asc' ? a.type.localeCompare(b.type) : b.type.localeCompare(a.type));
    } else if (sortedColumn === 'amount') {
      return transactionData.sort((a, b) => isSorted === 'asc' ? a.amount - b.amount : b.amount - a.amount);
    } else if (sortedColumn === 'date') {
      return transactionData.sort((a, b) => isSorted === 'asc' ? new Date(a.date) - new Date(b.date) : new Date(b.date) - new Date(a.date));
    }
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8">
      <Table variant="simple" size="md">
        <TableCaption className="text-zinc-400">Transaction History</TableCaption>
        <Thead>
          <Tr>
            <Th
              isSortEnabled
              onSort={handleSort}
              sortedColumn={sortedColumn}
              isSorted={isSorted}
              className="bg-zinc-600 text-zinc-400 hover:bg-zinc-700"
            >
              ID
              {sortedColumn === 'id' && (
                <span className="ml-2">
                  {isSorted === 'asc' ? <IoIosArrowDown /> : <IoIosArrowUp />}
                </span>
              )}
            </Th>
            <Th
              isSortEnabled
              onSort={handleSort}
              sortedColumn={sortedColumn}
              isSorted={isSorted}
              className="bg-zinc-600 text-zinc-400 hover:bg-zinc-700"
            >
              Name
              {sortedColumn === 'name' && (
                <span className="ml-2">
                  {isSorted === 'asc' ? <IoIosArrowDown /> : <IoIosArrowUp />}
                </span>
              )}
            </Th>
            <Th
              isSortEnabled
              onSort={handleSort}
              sortedColumn={sortedColumn}
              isSorted={isSorted}
              className="bg-zinc-600 text-zinc-400 hover:bg-zinc-700"
            >
              Type
              {sortedColumn === 'type' && (
                <span className="ml-2">
                  {isSorted === 'asc' ? <IoIosArrowDown /> : <IoIosArrowUp />}
                </span>
              )}
            </Th>
            <Th
              isSortEnabled
              onSort={handleSort}
              sortedColumn={sortedColumn}
              isSorted={isSorted}
              className="bg-zinc-600 text-zinc-400 hover:bg-zinc-700"
            >
              Amount
              {sortedColumn === 'amount' && (
                <span className="ml-2">
                  {isSorted === 'asc' ? <IoIosArrowDown /> : <IoIosArrowUp />}
                </span>
              )}
            </Th>
            <Th
              isSortEnabled
              onSort={handleSort}
              sortedColumn={sortedColumn}
              isSorted={isSorted}
              className="bg-zinc-600 text-zinc-400 hover:bg-zinc-700"
            >
              Date
              {sortedColumn === 'date' && (
                <span className="ml-2">
                  {isSorted === 'asc' ? <IoIosArrowDown /> : <IoIosArrowUp />}
                </span>
              )}
            </Th>
          </Tr>
        </Thead>
        <Tbody>
          {sortedTransactions().map((transaction) => (
            <Tr key={transaction.id}>
              <Td className="p-2 border border-zinc-800">{transaction.id}</Td>
              <Td className="p-2 border border-zinc-800">{transaction.name}</Td>
              <Td className="p-2 border border-zinc-800">{transaction.type}</Td>
              <Td className="p-2 border border-zinc-800">{transaction.amount}</Td>
              <Td className="p-2 border border-zinc-800">{transaction.date}</Td>
            </Tr>
          ))}
        </Tbody>
      </Table>
    </div>
  );
};

export default TransactionTable;

